'use client';

import Link from 'next/link';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Calendar, ArrowRight } from 'lucide-react';
import { appointments as allAppointments } from '@/lib/data';
import { format } from 'date-fns';
import { es } from 'date-fns/locale';
import { Appointment } from '@/lib/types';
import { useEffect, useState } from 'react';

export default function NextAppointment() {
  const [nextAppointment, setNextAppointment] = useState<Appointment | null>(null);

  useEffect(() => {
    // Sort appointments to find the soonest one
    const sortedAppointments = [...allAppointments].sort((a,b) => a.date.getTime() - b.date.getTime());
    setNextAppointment(sortedAppointments[0] || null);
  }, []);

  if (!nextAppointment) {
    return (
        <Card>
            <CardHeader>
                <CardTitle>Próxima Cita</CardTitle>
            </CardHeader>
            <CardContent>
                <p>Cargando...</p>
            </CardContent>
        </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle>Próxima Cita</CardTitle>
      </CardHeader>
      <CardContent>
        <div className="flex items-start gap-4">
          <Calendar className="h-8 w-8 text-primary" />
          <div>
            <p className="font-semibold">{nextAppointment.type}</p>
            <p className="text-sm text-muted-foreground">
              🗓 {format(nextAppointment.date, "eeee, dd 'de' MMMM", { locale: es })}
            </p>
          </div>
        </div>
        <Button asChild variant="link" className="px-0 mt-2">
          <Link href="/agenda">
            Ver todas las citas
            <ArrowRight className="ml-2 h-4 w-4" />
          </Link>
        </Button>
      </CardContent>
    </Card>
  );
}
